	RequiresTools:         runtime.RequiresTools,
}
seedRecentRouteAttemptsFromTracker(ctx, svc, workDir, time.Now().UTC())

cancelCtx, cancel := context.WithCancel(ctx)
defer cancel()

// When Harness is set and Model is empty, fizeau routes within the harness's
// eligible models using Profile/MinPower as the routing constraint. This is the
// well-formed request shape for profile-driven dispatch without an explicit model.
// fizeau returns ErrHarnessModelIncompatible (typed, non-nil) on pre-dispatch
// errors and a failed final event for post-dispatch errors.
start := time.Now().UTC()
events, err := svc.Execute(cancelCtx, req)
if err != nil {
	// A pre-dispatch Execute error means routing never produced a viable
	// dispatch — a provider-boundary failure. Wrap it with its typed
	// classification (ddx-3b721804) so callers recover the taxonomy via
	// errors.As instead of re-parsing free text, and so the failure
	// surfaces as a typed outcome_reason rather than generic execution_failed.
	return nil, &ProviderFailureError{
		Failure: ClassifyServiceExecuteError(err),
		Err:     fmt.Errorf("agent: execute: %w", err),
	}
}

workPhase := strings.TrimSpace(runtime.WorkLogPhase)
if workPhase == "" {
	workPhase = "do"
}
renderer := NewWorkLogRenderer(WorkLogRendererOptions{
	CurrentBeadID: runtime.Correlation["bead_id"],
	WorkPhase:     workPhase,
})
watchdog := &drainWatchdog{
	cancel:          cancel,
	idleTimeout:     idle,
	toolCallTimeout: time.Duration(ToolCallTimeout) * time.Millisecond,
}
onRouteResolved := func(harness, provider, model string) {
	harness = firstNonEmpty(harness, fizeauHarness(strings.TrimSpace(runtime.HarnessOverride)), fizeauHarness(strings.TrimSpace(pt.Harness)))
	provider = firstNonEmpty(provider, strings.TrimSpace(runtime.ProviderOverride), strings.TrimSpace(pt.Provider))
	model = firstNonEmpty(model, strings.TrimSpace(runtime.ModelOverride), strings.TrimSpace(pt.Model))
	route := providerRouteLabel(provider, model)
	now := time.Now().UTC()
	reaped, survivors := reapSupersededProviderChildren(context.Background(), os.Getpid(), route, harness, now)
	if len(reaped) > 0 {
		writeProviderChildCleanupArtifact(workDir, runtime.Correlation["attempt_id"], &providerChildCleanupReport{
			AttemptID:   runtime.Correlation["attempt_id"],
			BeadID:      runtime.Correlation["bead_id"],
			Trigger:     reasonSupersededProviderChild,
			ActiveRoute: firstNonEmpty(route, harness),
			ScannedAt:   now,
			Survivors:   survivors,
			Reaped:      reaped,
		})
	}
	if runtime.OnRouteResolved != nil {
		runtime.OnRouteResolved(harness, provider, model)
	}
}
final, routing, _ := drainServiceEventsWithRenderer(events, runtime.Output, renderer, watchdog, onRouteResolved)
if final == nil {
	// Provider process exited before emitting a final event — a harness-level
	// failure (crash, OOM, binary restart) the model never saw. Classify as
	// harness unavailable (retryable) so an unpinned worker can fall back to
	// another eligible route without operator intervention.
	return nil, &ProviderFailureError{
		Failure: ProviderFailure{
			Reason:     FailureModeProviderHarnessUnavailable,
			Retryable:  true,
			Disruption: FailureModeProviderHarnessUnavailable,
		},
		Err: fmt.Errorf("agent: provider process exited without emitting a final event"),
	}
}
finishedAt := time.Now().UTC()
elapsed := finishedAt.Sub(start)

result := &Result{
	Harness:    fizeauHarness(harness),
	Model:      model,
	DurationMS: int(elapsed.Milliseconds()),
}
if routing != nil {
	result.Provider = routing.Provider
	if routing.Model != "" {
		result.Model = routing.Model
	}
	if routing.Harness != "" {
		result.Harness = routing.Harness
	}
	if routing.Reason != "" {
		result.RouteReason = routing.Reason
	}
	if power, speed, cost, source := selectedRoutingCandidateMetrics(routing); power > 0 || speed > 0 || cost > 0 || source != "" {
		result.PredictedPower = power
		result.PredictedSpeedTPS = speed
		result.PredictedCostUSDPer1kTokens = cost
		result.PredictedCostSource = source
	}
}
if final != nil {
	// Normalized final text from the upstream harness (agent-32e8ff5e);
	// reviewer verdict extraction now parses this instead of raw stream
	// frames (ddx-7bc0c8d5).
	result.Output = final.FinalText
	if final.Usage != nil {
		// v0.9.1: Usage fields became *int (nullable).
		if final.Usage.InputTokens != nil {
			result.InputTokens = *final.Usage.InputTokens
		}
		if final.Usage.OutputTokens != nil {
			result.OutputTokens = *final.Usage.OutputTokens
		}
		if final.Usage.CacheReadTokens != nil {
			result.CachedTokens = *final.Usage.CacheReadTokens
		}
		if final.Usage.TotalTokens != nil {
			result.Tokens = *final.Usage.TotalTokens
		}
	}
	if final.CostUSD > 0 {
		result.CostUSD = final.CostUSD
	}
	result.ExitCode = final.ExitCode
	result.Error = final.Error
	if final.RoutingActual != nil {
		if result.Provider == "" {
			result.Provider = final.RoutingActual.Provider
		}
		if final.RoutingActual.Model != "" {
			result.Model = final.RoutingActual.Model
		}
		if final.RoutingActual.Harness != "" {
			result.Harness = final.RoutingActual.Harness
		}
		if final.RoutingActual.Power > 0 {
			result.ActualPower = final.RoutingActual.Power
		}
	}
	if final.SessionLogPath != "" {
		result.AgentSessionID = final.SessionLogPath
	}
}
result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
normalizeServiceFinalExitCode(result)

package agent

import (
	"context"
	"fmt"
	"net/url"
	"path/filepath"
	"strconv"
	"strings"
	"time"
	"unicode"

	agentlib "github.com/easel/fizeau"
	// Import the configinit package for its init() side-effect: it triggers
	// agent's internal/config init which registers the config loader into
	// agentlib so that agentlib.New(ServiceOptions{ConfigPath:…}) can resolve
	// provider configuration without a separate adapter. configinit is the
	// public marker package exposed for this purpose after agent v0.5.0
	// moved internal/config out of the public surface.
	ddxconfig "github.com/DocumentDrivenDX/ddx/internal/config"
	_ "github.com/easel/fizeau/configinit"
)

// DefaultProviderRequestTimeout is the per-request wall-clock cap for
// providers. It guards against a provider that emits headers but then stalls
// entirely — a scenario the idle-read timeout below catches for streaming
// providers, but which also applies to non-streaming Chat calls where no body
// bytes arrive at all.
//
// To override per-project, set agent.endpoints.<name>.request_timeout_seconds
// in .ddx/config.yaml, or pass --request-timeout DURATION to execute-bead /
// work for one-off debugging.
const DefaultProviderRequestTimeout = 15 * time.Minute

// DefaultProviderIdleReadTimeout bounds the maximum idle gap between stream
// deltas. This is the primary stalled-TCP-socket defense: when no body bytes
// arrive for 5 continuous minutes the provider is assumed hung and the call
// fails.
const DefaultProviderIdleReadTimeout = 5 * time.Minute

// ResolveProviderRequestTimeout returns the effective wall-clock cap for a
// single Chat/ChatStream call. Resolution order:
//  1. override if > 0 (from --request-timeout CLI flag via ResolvedConfig)
//  2. agent.endpoints[n].request_timeout_seconds in .ddx/config.yaml for
//     the named provider endpoint
//  3. DefaultProviderRequestTimeout (15 min)
//
// The idle-read timeout (DefaultProviderIdleReadTimeout, 5 min) is a
// separate mechanism and is NOT affected by this function.
func ResolveProviderRequestTimeout(workDir, providerName, _ string, override time.Duration) time.Duration {
	if override > 0 {
		return override
	}
	if workDir != "" && providerName != "" {
		if cfg, err := ddxconfig.LoadWithWorkingDir(workDir); err == nil {
			if t := endpointRequestTimeout(cfg, providerName); t > 0 {
				return t
			}
		}
	}
	return DefaultProviderRequestTimeout
}

// endpointRequestTimeout looks up the request_timeout_seconds for the named
// provider in cfg.Agent.Endpoints. Returns 0 if not configured or not found.
func endpointRequestTimeout(cfg *ddxconfig.Config, providerName string) time.Duration {
	if cfg == nil || cfg.Agent == nil {
		return 0
	}
	for i, ep := range cfg.Agent.Endpoints {
		if ep.RequestTimeoutSeconds <= 0 {
			continue
		}
		name, _, err := endpointProviderEntry(ep, i)
		if err != nil {
			continue
		}
		if name == providerName {
			return time.Duration(ep.RequestTimeoutSeconds) * time.Second
		}
	}
	return 0
}

// NewServiceFromWorkDir constructs the normal execution FizeauService for a DDx
// project. Fizeau owns provider config, provider discovery, include-by-default
// semantics, and policy routing; DDx project endpoint blocks are used by status
// surfaces below, not as an execution-time replacement for Fizeau config.
//
// NOTE on goroutine lifecycle: the returned service spawns background probe /
// quota-refresh / aliveness goroutines that are tied to
// ServiceOptions.QuotaRefreshContext (default context.Background). Short-lived
// callers (HTTP handlers, one-off CLI subcommands, tests) MUST prefer
// NewServiceFromWorkDirCtx and pass a request-scoped context so those
// goroutines are cancelled when the caller is done. Otherwise the goroutines
// leak for the lifetime of the process and accumulate under repeated calls
// (see bead ddx-server-fizeau-leak).
func NewServiceFromWorkDir(workDir string) (agentlib.FizeauService, error) {
	return agentlib.New(agentlib.ServiceOptions{})
}

// NewServiceFromWorkDirCtx is the context-scoped variant of
// NewServiceFromWorkDir. Cancelling ctx terminates the background quota
// refresh, quota recovery probe, and aliveness probe goroutines spawned by
// the returned service. Callers that issue requests at HTTP / RPC granularity
// SHOULD use this form with their request context to avoid goroutine leaks.
func NewServiceFromWorkDirCtx(ctx context.Context, workDir string) (agentlib.FizeauService, error) {
	if ctx == nil {
		ctx = context.Background()
	}
	return agentlib.New(agentlib.ServiceOptions{QuotaRefreshContext: ctx})
}

// NewPreflightServiceFromWorkDir constructs a service for route/model inventory
// preflight paths. It disables Fizeau's background quota/aliveness/probe loops at
// construction time; callers still pass live request contexts to ListModels,
// ResolveRoute, and other foreground service methods.
func NewPreflightServiceFromWorkDir(workDir string) (agentlib.FizeauService, error) {
	ctx, cancel := context.WithCancel(context.Background())
	cancel()
	return NewServiceFromWorkDirCtx(ctx, workDir)
}

// NewStatusProbeServiceFromWorkDir constructs a service for status surfaces
// without pre-filtering .legacy agent endpoints by /models reachability. The
// returned service still probes when ListProviders is called, but unreachable
// configured endpoints remain present in the result as unreachable rows.
//
// See the NewServiceFromWorkDir doc-comment for the goroutine-lifecycle
// caveat; prefer NewStatusProbeServiceFromWorkDirCtx for request-scoped use.
func NewStatusProbeServiceFromWorkDir(workDir string) (agentlib.FizeauService, error) {
	return newStatusProbeService(context.Background(), workDir)
}

// NewStatusProbeServiceFromWorkDirCtx is the context-scoped variant of
// NewStatusProbeServiceFromWorkDir. Cancelling ctx terminates the spawned
// background probe / quota-refresh goroutines.
func NewStatusProbeServiceFromWorkDirCtx(ctx context.Context, workDir string) (agentlib.FizeauService, error) {
	if ctx == nil {
		ctx = context.Background()
	}
	return newStatusProbeService(ctx, workDir)
}

func newStatusProbeService(ctx context.Context, workDir string) (agentlib.FizeauService, error) {
	opts := agentlib.ServiceOptions{
		ConfigPath:          filepath.Join(workDir, "config.yaml"),
		QuotaRefreshContext: ctx,
	}
	sc, err := serviceConfigFromDDxEndpointsNoFilter(workDir)
	if err != nil {
		return nil, err
	}
	if sc != nil {
		opts.ServiceConfig = sc
	}
	return agentlib.New(opts)
}

type endpointServiceConfig struct {
	providers   map[string]agentlib.ServiceProviderEntry
	names       []string
	defaultName string
	workDir     string
}

func serviceConfigFromDDxEndpointsNoFilter(workDir string) (agentlib.ServiceConfig, error) {
	cfg, err := ddxconfig.LoadWithWorkingDir(workDir)
	if err != nil {
		return nil, err
	}
	if cfg.Agent == nil || len(cfg.Agent.Endpoints) == 0 {
		return nil, nil
	}
	return newEndpointServiceConfigWithoutLiveFilter(cfg.Agent.Endpoints, workDir)
}

// ConfiguredProviderSnapshots returns endpoint-provider rows from .ddx config
// without probing their /models endpoints. It is used by UI surfaces that must
// first-paint from last-known or configured state and refresh live probes
// asynchronously.
func ConfiguredProviderSnapshots(workDir string) ([]agentlib.ProviderInfo, bool, error) {
	cfg, err := ddxconfig.LoadWithWorkingDir(workDir)
	if err != nil {
		return nil, false, err
	}
	if cfg.Agent == nil || len(cfg.Agent.Endpoints) == 0 {
		return nil, false, nil
	}
	out := make([]agentlib.ProviderInfo, 0, len(cfg.Agent.Endpoints))
	for i, endpoint := range cfg.Agent.Endpoints {
		name, entry, err := endpointProviderEntry(endpoint, i)
		if err != nil {
			return nil, true, err
		}
		out = append(out, agentlib.ProviderInfo{
			Name:         name,
			Type:         strings.ToLower(strings.TrimSpace(entry.Type)),
			BaseURL:      entry.BaseURL,
			Endpoints:    append([]agentlib.ServiceProviderEndpoint(nil), entry.Endpoints...),
			Status:       "unknown",
			DefaultModel: entry.Model,
			IsDefault:    i == 0,
		})
	}
	return out, true, nil
}

func newEndpointServiceConfigWithoutLiveFilter(endpoints []ddxconfig.AgentEndpoint, workDir string) (*endpointServiceConfig, error) {
	sc := &endpointServiceConfig{
		providers: make(map[string]agentlib.ServiceProviderEntry),
		workDir:   workDir,
	}
	for i, endpoint := range endpoints {
		name, entry, err := endpointProviderEntry(endpoint, i)
		if err != nil {
			return nil, err
		}
		sc.providers[name] = entry
		sc.names = append(sc.names, name)

