package agent

import (
	"context"
	"path/filepath"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
)

const (
	providerChildActionTerminated = "terminated"
	reasonSupersededProviderChild = "superseded_provider_child"
	reasonRunningPhaseGuard       = "running_phase_non_route_provider_child"
	reasonAttemptEnded            = "attempt_ended"
	providerChildCleanupArtifact  = "provider-children.json"
)

// runningProviderGuardInterval is how often the running-phase guard re-scans
// the worker's provider-CLI descendants while an attempt is in flight. Provider
// CLIs spawned after route resolution (the dogfooded Codex/Gemini fan-out) are
// reaped within one interval instead of surviving until attempt-end cleanup.
const runningProviderGuardInterval = 2 * time.Second

var providerCLINames = map[string]struct{}{
	"claude":   {},
	"codex":    {},
	"gemini":   {},
	"opencode": {},
	"pi":       {},
}

type providerChildProcess struct {
	PID       int
	Provider  string
	Command   string
	StartedAt time.Time
}

type providerChildReapRecord struct {
	PID        int     `json:"pid"`
	Provider   string  `json:"provider"`
	Command    string  `json:"command,omitempty"`
	AgeSeconds float64 `json:"age_seconds"`
	Action     string  `json:"action"`
	Reason     string  `json:"reason"`
}

type providerChildCleanupReport struct {
	AttemptID   string                       `json:"attempt_id"`
	BeadID      string                       `json:"bead_id"`
	Trigger     string                       `json:"trigger"`
	ActiveRoute string                       `json:"active_route,omitempty"`
	ScannedAt   time.Time                    `json:"scanned_at"`
	Survivors   []workerstatus.ProviderChild `json:"survivors,omitempty"`
	Reaped      []providerChildReapRecord    `json:"reaped,omitempty"`
	ScanErr     string                       `json:"scan_error,omitempty"`
}

var providerChildScanner = func(ctx context.Context, rootPID int, now time.Time) ([]providerChildProcess, error) {
	return scanProviderChildProcessesImpl(ctx, rootPID, now)
}

var terminateProviderChild = terminateProviderChildImpl

func providerForCommand(cmdline string) string {
	parts := strings.Fields(strings.TrimSpace(cmdline))
	if len(parts) == 0 {
		return ""
	}
	base := filepath.Base(parts[0])
	if _, ok := providerCLINames[base]; ok {
		return base
	}
	// Node-wrapper detection: "node /path/to/provider-cli ..." where argv[0]
	// is the Node.js runtime and argv[1] is the provider CLI path
	// (e.g. Gemini installed via npm: "node /home/linuxbrew/.linuxbrew/bin/gemini").
	if base == "node" && len(parts) >= 2 {
		if argBase := filepath.Base(parts[1]); argBase != "" && argBase != "." {
			if _, ok := providerCLINames[argBase]; ok {
				return argBase
			}
		}
	}
	return ""
}

func providerRouteLabel(provider, model string) string {
	route := strings.TrimSpace(provider)
	if route != "" && strings.TrimSpace(model) != "" {
		route += "/" + strings.TrimSpace(model)
	}
	return route
}

func routeOwnsProvider(provider string, routeTokens ...string) bool {
	p := strings.ToLower(strings.TrimSpace(provider))
	if p == "" {
		return false
	}
	for _, tok := range routeTokens {
		tok = strings.ToLower(strings.TrimSpace(tok))
		if tok == "" {
			continue
		}
		if tok == p {
			return true
		}
		if seg := strings.SplitN(tok, "/", 2); len(seg) > 0 && seg[0] == p {
			return true
		}
	}
	return false
}

func scanProviderChildrenForStatus(ctx context.Context, rootPID int, routeLabel, harness, phase string, now time.Time) []workerstatus.ProviderChild {
	procs, err := providerChildScanner(ctx, rootPID, now)
	if err != nil || len(procs) == 0 {
		return nil
	}
	activeOwner := activeRouteOwner(routeLabel, harness)
	out := make([]workerstatus.ProviderChild, 0, len(procs))
	for _, proc := range procs {
		out = append(out, providerChildStatus(proc, routeLabel, harness, activeOwner, phase, now))
	}
	return out
}

// providerChildStatus renders one scanned provider process as a status entry,
// marking it route-owned (RouteOwner set) or, when the active route is known
// and the provider does not match it, non-route with an operator-facing
// diagnostic. Non-route children observed without a known route are reported
// plain so an early scan never mislabels a child the guard cannot yet judge.
func providerChildStatus(proc providerChildProcess, routeLabel, harness, activeOwner, phase string, now time.Time) workerstatus.ProviderChild {
	child := workerstatus.ProviderChild{
		PID:        proc.PID,
		Provider:   proc.Provider,
		Harness:    proc.Provider,
		Phase:      phase,
		AgeSeconds: childAgeSeconds(proc, now),
	}
	if routeOwnsProvider(proc.Provider, routeLabel, harness) {
		child.RouteOwner = activeOwner
		return child
	}
	if activeOwner != "" {
		child.NonRoute = true
		child.Diagnostic = nonRouteProviderDiagnostic(proc.Provider, activeOwner)
	}
	return child
}

// activeRouteOwner is the human-facing owner label for the active route:
// the route label when present, otherwise the harness. Empty when neither is
// known (route not yet resolved).
func activeRouteOwner(routeLabel, harness string) string {
	if owner := strings.TrimSpace(routeLabel); owner != "" {
		return owner
	}
	return strings.TrimSpace(harness)
}

func nonRouteProviderDiagnostic(provider, owner string) string {
	if owner == "" {
		return "non-route provider " + provider + " terminated by running-phase guard"
	}
	return "non-route provider " + provider + " terminated by running-phase guard (active route " + owner + ")"
}

// runningProviderChildGuard performs one running-phase sweep of the worker's
// provider-CLI descendants. Children whose provider matches the active
// route/harness are preserved and reported as route-owned; every other provider
// CLI is terminated by process group (taking grandchildren such as Gemini's
// Node worker with it) and reported as non-route with an operator-attention
// diagnostic. When the active route is not yet known (route and harness both
// empty) the guard observes without reaping, so it never quarantines a child it
// cannot yet attribute. Returns the status view and the reap evidence records.
func runningProviderChildGuard(ctx context.Context, rootPID int, routeLabel, harness, phase string, now time.Time) ([]workerstatus.ProviderChild, []providerChildReapRecord) {
	procs, err := providerChildScanner(ctx, rootPID, now)
	if err != nil || len(procs) == 0 {
		return nil, nil
	}
	activeOwner := activeRouteOwner(routeLabel, harness)
	children := make([]workerstatus.ProviderChild, 0, len(procs))
	var reaped []providerChildReapRecord
	for _, proc := range procs {
		child := providerChildStatus(proc, routeLabel, harness, activeOwner, phase, now)
		if child.NonRoute {
			terminateProviderChild(proc.PID)
			reaped = append(reaped, providerChildReapRecord{
				PID:        proc.PID,
				Provider:   proc.Provider,
				Command:    proc.Command,
				AgeSeconds: child.AgeSeconds,
				Action:     providerChildActionTerminated,
				Reason:     reasonRunningPhaseGuard,
			})
		}
		children = append(children, child)
	}
	return children, reaped
}

// runningProviderGuard is the attempt-scoped watchdog that drives
// runningProviderChildGuard on a ticker for the duration of attemptBackend.Run.
// It is owned by ExecuteBeadWithConfig (the shared ddx work / ddx try attempt
// path). The active route is seeded from any pinned harness/model and refreshed
// via UpdateRoute when fizeau resolves the route mid-attempt.
type runningProviderGuard struct {
	projectRoot string
	beadID      string
	attemptID   string
	rootPID     int
	interval    time.Duration

	mu         sync.Mutex
	routeLabel string
	harness    string
	reaped     []providerChildReapRecord
}

func newRunningProviderGuard(projectRoot, beadID, attemptID string, rootPID int) *runningProviderGuard {
	return &runningProviderGuard{
		projectRoot: projectRoot,
		beadID:      beadID,
		attemptID:   attemptID,
		rootPID:     rootPID,
		interval:    runningProviderGuardInterval,
	}
}

// UpdateRoute records the active route. Non-empty harness/route values overwrite
// the prior values; empty values are ignored so a partial resolution never
// blanks a previously known route.
func (g *runningProviderGuard) UpdateRoute(harness, provider, model string) {
	if g == nil {
		return
	}
	g.mu.Lock()
	defer g.mu.Unlock()
	if h := strings.TrimSpace(harness); h != "" {
		g.harness = h
	}
	if r := providerRouteLabel(provider, model); r != "" {
		g.routeLabel = r
	}
}

func (g *runningProviderGuard) snapshotRoute() (string, string) {
	g.mu.Lock()
	defer g.mu.Unlock()
	return g.routeLabel, g.harness
}

// Reaped returns a copy of the running-phase reap evidence accumulated so far,
// so attempt-end cleanup can fold it into the final provider-children.json.
func (g *runningProviderGuard) Reaped() []providerChildReapRecord {
	if g == nil {

	// a "gemini" provider; the backgrounded fake node inherits gemini's process
	// group (non-interactive sh keeps no separate group for background jobs), so
	// it is a grandchild reachable only by killing the group.
	cmd := exec.Command(geminiBin, "-c", `"$1" 120 & echo $! > "$2"; wait`, "gemini", nodeBin, pidFile)
	cmd.SysProcAttr = &syscall.SysProcAttr{Setpgid: true}
	if err := cmd.Start(); err != nil {
		t.Fatalf("start fake gemini: %v", err)
	}
	geminiPID := cmd.Process.Pid
	go func() { _, _ = cmd.Process.Wait() }()
	t.Cleanup(func() { _ = syscall.Kill(-geminiPID, syscall.SIGKILL) })

	waitForProviderChildren(t, os.Getpid(), geminiPID)
	nodePID := waitForPIDFile(t, pidFile)

	_, reaped := runningProviderChildGuard(context.Background(), os.Getpid(), "claude/sonnet", "", "running", time.Now().UTC())

	assertProcessGone(t, geminiPID)
	assertProcessGone(t, nodePID)

	var sawGemini bool
	for _, r := range reaped {
		if r.Provider == "gemini" {
			sawGemini = true
		}
	}
	if !sawGemini {
		t.Fatalf("running guard must reap the gemini parent; got %+v", reaped)
	}
}

func TestAttemptEndCleanupStillReapsAllProviderChildren(t *testing.T) {
	dir := t.TempDir()
	claudePID := startFakeProviderChild(t, dir, "claude")
	codexPID := startFakeProviderChild(t, dir, "codex")
	waitForProviderChildren(t, os.Getpid(), claudePID, codexPID)

	reaped := reapAllProviderChildren(context.Background(), os.Getpid(), time.Now().UTC())

	// The attempt-end backstop reaps every provider child regardless of route,
	// including the active-route claude child the running guard would preserve.
	assertProcessGone(t, claudePID)
	assertProcessGone(t, codexPID)

	reapedProviders := map[string]bool{}
	for _, r := range reaped {
		reapedProviders[r.Provider] = true
		if r.Reason != reasonAttemptEnded {
			t.Fatalf("attempt-end reap reason for %s = %q, want %q", r.Provider, r.Reason, reasonAttemptEnded)
		}
	}
	if !reapedProviders["claude"] || !reapedProviders["codex"] {
		t.Fatalf("attempt-end backstop must reap all provider children; got %+v", reaped)
	}
}

func waitForPIDFile(t *testing.T, path string) int {
	t.Helper()
	deadline := time.Now().Add(3 * time.Second)
	for time.Now().Before(deadline) {
		data, err := os.ReadFile(path)
		if err == nil {
			if pid, convErr := strconv.Atoi(strings.TrimSpace(string(data))); convErr == nil && pid > 0 {
				return pid
			}
		}
		time.Sleep(25 * time.Millisecond)
	}
	t.Fatalf("pid file %s was not written", path)
	return 0
}

func TestAttemptEndReapsAllProviderChildren(t *testing.T) {
	for _, mode := range []string{"success", "failure", "interrupt"} {
		t.Run(mode, func(t *testing.T) {
			beadID := "ddx-provider-end-" + mode
			projectRoot, gitOps := setupProcessCleanupAttempt(t, beadID)
			binDir := t.TempDir()
			runner := newProviderChildRunner(t, binDir, "codex", mode)

			ctx := context.Background()
			var cancel context.CancelFunc
			if mode == "interrupt" {
				ctx, cancel = context.WithCancel(ctx)
				defer cancel()
			}

			done := make(chan struct{})
			go func() {
				_, _ = ExecuteBeadWithConfig(ctx, projectRoot, beadID, processCleanupConfig(), ExecuteBeadRuntime{
					AgentRunner: runner,
				}, gitOps)
				close(done)
			}()

			pid := <-runner.started
			if mode == "interrupt" {
				cancel()
			}
			select {
			case <-done:
			case <-time.After(10 * time.Second):
				t.Fatal("ExecuteBeadWithConfig did not return")
			}
			assertProcessGone(t, pid)
		})
	}
}

type providerChildRunner struct {
	bin     string
	started chan int
	mode    string
}

func newProviderChildRunner(t *testing.T, dir, provider, mode string) *providerChildRunner {
	t.Helper()
	sleepPath, err := exec.LookPath("sleep")
	if err != nil {
		t.Skipf("sleep not available: %v", err)
	}
	bin := filepath.Join(dir, provider)
	if err := os.Symlink(sleepPath, bin); err != nil {
		t.Fatalf("symlink fake %s: %v", provider, err)
	}
	return &providerChildRunner{bin: bin, started: make(chan int, 1), mode: mode}
}

func (r *providerChildRunner) Run(opts RunArgs) (*Result, error) {
	cmd := exec.Command(r.bin, "120")
	cmd.SysProcAttr = &syscall.SysProcAttr{Setpgid: true}
	if err := cmd.Start(); err != nil {
		return &Result{ExitCode: 1, Error: err.Error()}, nil
	}
	pid := cmd.Process.Pid
	go func() { _, _ = cmd.Process.Wait() }()
	r.started <- pid
	switch r.mode {
	case "interrupt":
		ctx := opts.Context
		if ctx == nil {
			ctx = context.Background()
		}
		<-ctx.Done()
		return &Result{ExitCode: 1, Error: ctx.Err().Error()}, nil
	case "failure":
		return &Result{ExitCode: 1, Error: "synthetic failure"}, nil
	default:
		return &Result{ExitCode: 0}, nil
	}
}

func waitForProviderChildren(t *testing.T, rootPID int, pids ...int) {
	t.Helper()
	deadline := time.Now().Add(3 * time.Second)
	for time.Now().Before(deadline) {
		procs, err := providerChildScanner(context.Background(), rootPID, time.Now().UTC())
		if err == nil {
			seen := map[int]bool{}
			for _, p := range procs {
				seen[p.PID] = true
			}
			all := true
			for _, pid := range pids {
				if !seen[pid] {
					all = false
					break
				}
			}
			if all {
				return
			}
		}
		time.Sleep(25 * time.Millisecond)
	}
	t.Fatalf("scanner did not observe all provider children %v under pid %d", pids, rootPID)
}

// TestProviderForCommandDetectsNodeWrappedGemini proves that
// providerForCommand correctly classifies "node /path/to/gemini ..." as
// provider "gemini" while ordinary non-provider Node invocations return empty.
func TestProviderForCommandDetectsNodeWrappedGemini(t *testing.T) {
	cases := []struct {
		cmdline  string
		expected string
	}{
		{"node /home/linuxbrew/.linuxbrew/bin/gemini --interactive", "gemini"},
		{"node /usr/local/bin/gemini", "gemini"},
		{"/usr/bin/node /opt/homebrew/bin/gemini --no-sandbox", "gemini"},
		{"/usr/bin/node /usr/local/bin/codex", "codex"},
		{"node /some/other/script.js", ""},
		{"node script.js", ""},
		{"node", ""},
		{"node -e 'console.log(1)'", ""},
		{"python /usr/local/bin/gemini", ""},
		{"gemini --interactive", "gemini"},
	}
	for _, tc := range cases {
		got := providerForCommand(tc.cmdline)
		if got != tc.expected {
			t.Errorf("providerForCommand(%q) = %q, want %q", tc.cmdline, got, tc.expected)
		}
	}
}

// TestRunningProviderGuardReapsNodeWrappedGeminiProcessGroup starts a fake
// Node wrapper process whose argv includes a gemini path and proves the running
// guard reports and reaps that Gemini process group while preserving the
// active-route Claude child.
func TestRunningProviderGuardReapsNodeWrappedGeminiProcessGroup(t *testing.T) {
	shPath, err := exec.LookPath("sh")
	if err != nil {
		t.Skipf("sh not available: %v", err)
	}
	dir := t.TempDir()

	// geminiScript is the script that sh will interpret; sh's own process
	// retains the original argv (nodeBin, geminiScript) visible in ps.
	geminiScript := filepath.Join(dir, "gemini")
	if err := os.WriteFile(geminiScript, []byte("#!/bin/sh\nsleep 120\n"), 0755); err != nil {
		t.Fatalf("write gemini script: %v", err)
	}

	// nodeBin is the fake "node" path used as argv[0]; the actual binary run
	// is sh so that the process blocks while ps shows "node /tmp/.../gemini".
	nodeBin := filepath.Join(dir, "node")

	// Run sh with custom argv: [nodeBin, geminiScript].  ps reports the command
	// as "/tmp/.../node /tmp/.../gemini" — the real-world Node-wrapper shape.
	cmd := &exec.Cmd{
		Path:        shPath,
		Args:        []string{nodeBin, geminiScript},
		SysProcAttr: &syscall.SysProcAttr{Setpgid: true},
	}
	if err := cmd.Start(); err != nil {
		t.Fatalf("start fake node-wrapped gemini: %v", err)
	}
	nodeGeminiPID := cmd.Process.Pid
	go func() { _, _ = cmd.Process.Wait() }()
	t.Cleanup(func() { _ = syscall.Kill(-nodeGeminiPID, syscall.SIGKILL) })

	claudePID := startFakeProviderChild(t, dir, "claude")
	waitForProviderChildren(t, os.Getpid(), claudePID, nodeGeminiPID)

	children, reaped := runningProviderChildGuard(context.Background(), os.Getpid(), "claude/sonnet", "", "running", time.Now().UTC())

	assertProcessGone(t, nodeGeminiPID)

	var sawGeminiReaped bool
	for _, r := range reaped {
		if r.Provider == "gemini" {
			sawGeminiReaped = true
			if r.Reason != reasonRunningPhaseGuard {
				t.Fatalf("node-wrapped gemini reap reason = %q, want %q", r.Reason, reasonRunningPhaseGuard)
			}
		}
	}
	if !sawGeminiReaped {
		t.Fatalf("running guard must reap node-wrapped gemini; reaped=%+v", reaped)
	}

	byProvider := map[string]workerstatus.ProviderChild{}
	for _, c := range children {
		byProvider[c.Provider] = c
	}
	if claude, ok := byProvider["claude"]; !ok || claude.RouteOwner == "" || claude.NonRoute {
		t.Fatalf("claude must be route-owned: %+v", byProvider["claude"])
	}
	gemini, ok := byProvider["gemini"]
	if !ok {
		t.Fatalf("gemini must appear in status view: %+v", children)
	}
	if !gemini.NonRoute || gemini.RouteOwner != "" || gemini.Diagnostic == "" {
		t.Fatalf("node-wrapped gemini must be non-route with diagnostic: %+v", gemini)
	}
}

//go:build linux

package agent

import (
	"bytes"
	"context"
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"
)

type procExecutionCleanupAttemptProcessScanner struct {
	now func() time.Time
}

func newExecutionCleanupAttemptProcessScannerImpl() executionCleanupAttemptProcessScanner {
	return &procExecutionCleanupAttemptProcessScanner{now: time.Now}
}

func (s *procExecutionCleanupAttemptProcessScanner) Scan(ctx context.Context) ([]executionCleanupAttemptProcess, error) {
	entries, err := os.ReadDir("/proc")
	if err != nil {
		return nil, fmt.Errorf("read /proc: %w", err)
	}
	bootTime := readExecutionCleanupBootTime("/proc/stat")
	out := make([]executionCleanupAttemptProcess, 0)
	for _, entry := range entries {
		if ctx != nil && ctx.Err() != nil {
			return nil, ctx.Err()
		}
		if !entry.IsDir() {
			continue
		}
		pid, err := strconv.Atoi(entry.Name())
		if err != nil || pid <= 0 {
			continue
		}
		proc, ok := s.inspect(pid, bootTime)
		if !ok {
			continue
		}
		out = append(out, proc)
	}
	return out, nil
}

func (s *procExecutionCleanupAttemptProcessScanner) inspect(pid int, bootTime time.Time) (executionCleanupAttemptProcess, bool) {
	base := filepath.Join("/proc", strconv.Itoa(pid))
	cmdlineRaw, err := os.ReadFile(filepath.Join(base, "cmdline"))
	if err != nil {
		return executionCleanupAttemptProcess{}, false
	}
	cwd, _ := os.Readlink(filepath.Join(base, "cwd"))
	ppid, pgid, startedAt, ok := readExecutionCleanupProcessStat(filepath.Join(base, "stat"), bootTime, s.now)
	if !ok {
		return executionCleanupAttemptProcess{}, false
	}
	cmdline := decodeExecutionCleanupCmdline(cmdlineRaw)
	proc := executionCleanupAttemptProcessFromWorkerStatus(cmdline, cwd, pid, ppid, pgid, startedAt)
	if proc.Worktree == "" {
		return executionCleanupAttemptProcess{}, false
	}
	return proc, true
}

func decodeExecutionCleanupCmdline(raw []byte) string {
	if len(raw) == 0 {
		return ""
	}
	if raw[len(raw)-1] == 0 {
		raw = raw[:len(raw)-1]
	}
	parts := bytes.Split(raw, []byte{0})
	out := make([]string, 0, len(parts))
	for _, part := range parts {
		if len(part) == 0 {
			continue
		}
		out = append(out, string(part))
	}
	return strings.Join(out, " ")
}

func readExecutionCleanupBootTime(statPath string) time.Time {
	data, err := os.ReadFile(statPath)
	if err != nil {
		return time.Time{}
	}
	for _, line := range strings.Split(string(data), "\n") {
		if !strings.HasPrefix(line, "btime ") {
			continue
		}
		fields := strings.Fields(line)
		if len(fields) < 2 {
			continue
		}
		sec, err := strconv.ParseInt(fields[1], 10, 64)
		if err != nil {
			return time.Time{}
		}
		return time.Unix(sec, 0)
	}
	return time.Time{}
}

func readExecutionCleanupProcessStat(statPath string, bootTime time.Time, now func() time.Time) (ppid int, pgid int, startedAt time.Time, ok bool) {
	data, err := os.ReadFile(statPath)
	if err != nil {
		return 0, 0, time.Time{}, false
	}
	close := strings.LastIndex(string(data), ")")
	if close < 0 {
		return 0, 0, time.Time{}, false
	}
	tail := strings.Fields(string(data[close+1:]))
	if len(tail) < 20 {
		return 0, 0, time.Time{}, false
	}
	parsedPPID, err := strconv.Atoi(tail[1])
	if err != nil {
		return 0, 0, time.Time{}, false
	}
	parsedPGID, err := strconv.Atoi(tail[2])
	if err != nil {
		return 0, 0, time.Time{}, false
	}
	startClk, err := strconv.ParseInt(tail[19], 10, 64)
	if err != nil {
		return 0, 0, time.Time{}, false
	}
	if !bootTime.IsZero() {
		seconds := float64(startClk) / 100.0
		startedAt = bootTime.Add(time.Duration(seconds * float64(time.Second)))
	}
	if startedAt.IsZero() {
		if now == nil {
			now = time.Now
		}
		startedAt = now().UTC()
	}
	return parsedPPID, parsedPGID, startedAt.UTC(), true
}

// Package workerstatus reports on live "ddx work" / "ddx try" processes,
// scoped to a specific project root by default.
//
// Operators and agents asking "is the worker still working beads?" must be
// able to answer the question for one project at a time. A global process
// scan ("ps aux | grep ddx work") returns workers from every checkout on the
// machine and produces a misleading "yes, working" signal when the worker
// belongs to a different repository. This package filters live workers by
// the resolved project root so the answer always matches the question.
package workerstatus

import (
	"context"
	"path/filepath"
	"regexp"
	"strings"
	"time"
)

// LiveWorker describes one running ddx worker process.
type LiveWorker struct {
	PID                int             `json:"pid"`
	Command            string          `json:"command"`
	StartedAt          time.Time       `json:"started_at"`
	AgeSeconds         float64         `json:"age_seconds"`
	Age                string          `json:"age"`
	ProjectRoot        string          `json:"project_root"`
	BeadID             string          `json:"bead_id,omitempty"`
	AttemptID          string          `json:"attempt_id,omitempty"`
	Phase              string          `json:"phase,omitempty"`
	Message            string          `json:"message,omitempty"`
	ChildPID           int             `json:"child_pid,omitempty"`
	LastActivityAt     time.Time       `json:"last_activity_at,omitempty"`
	ExecutionWorktree  string          `json:"execution_worktree,omitempty"`
	Cwd                string          `json:"cwd,omitempty"`
	ProviderChildren   []ProviderChild `json:"provider_children,omitempty"`
	StaleMonitorShells int             `json:"stale_monitor_shells,omitempty"`
}

// ProviderChild describes a provider CLI subprocess observed under a worker.
//
// RouteOwner is set when the child's provider matches the worker's active
// route/harness; such a child is legitimate route work and is never reaped.
// NonRoute is set on a provider CLI whose provider does not match the active
// route — an unrelated harness the running-phase guard terminates — and
// Diagnostic carries an operator-facing explanation for that quarantine.
type ProviderChild struct {
	PID        int     `json:"pid"`
	Provider   string  `json:"provider"`
	Harness    string  `json:"harness,omitempty"`
	RouteOwner string  `json:"route_owner,omitempty"`
	Phase      string  `json:"phase,omitempty"`
	AgeSeconds float64 `json:"age_seconds"`
	NonRoute   bool    `json:"non_route,omitempty"`
	Diagnostic string  `json:"diagnostic,omitempty"`
}

// Scanner discovers live ddx worker processes on the host.
type Scanner interface {
	Scan(ctx context.Context) ([]LiveWorker, error)
}

// New returns the platform-appropriate Scanner. On Linux this reads /proc.
// On other platforms it returns an empty list; the caller's tests and the
// --all-projects escape hatch remain meaningful regardless.
func New() Scanner {
	return newSystemScanner()
}

// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
// total) embedded in argv strings or worktree paths.
var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)

// executionWorktreePattern matches the conventional execute-bead worktree
// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
// in a path. The directory name is enough to identify the worktree even when
// the surrounding path is unconventional.
var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)

// InferBead extracts a bead ID and execution worktree path from the worker's
// command line and current working directory. It returns the longest worktree
// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
// the inline worker has chdir'd into the isolated worktree), and the first
// bead ID matched in either the command line or the worktree path.
//
// Either return value may be empty when no signal is present, which is the
// expected case for a long-running `ddx work` drain that has not yet started
// a specific bead.
func InferBead(cmdline, cwd string) (beadID, worktree string) {
	worktree = extractWorktreePath(cwd)
	if worktree == "" {
		worktree = extractWorktreePath(cmdline)
	}

	if m := beadIDPattern.FindString(worktree); m != "" {
		beadID = m
	}
	if beadID == "" {
		if m := beadIDPattern.FindString(cmdline); m != "" {
			beadID = m
		}
	}
	if beadID == "" {
		if m := beadIDPattern.FindString(cwd); m != "" {
			beadID = m
		}
	}
	return beadID, worktree
}

func extractWorktreePath(s string) string {
	if s == "" {
		return ""
	}
	if !strings.Contains(s, ".execute-bead-wt-") {
		return ""
	}
	matches := executionWorktreePattern.FindStringIndex(s)
	if matches == nil {
		return ""
	}
	start := matches[0]
	end := matches[1]
	for start > 0 {
		r := s[start-1]
		if r == ' ' || r == '\x00' || r == '\t' {
			break
		}
		start--
	}
	for end < len(s) {
		r := s[end]
		if r == ' ' || r == '\x00' || r == '\t' {
			break
		}
		end++
	}
	return s[start:end]
}

// FilterByProject returns workers whose ProjectRoot resolves to the same path
// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
// filepath.EvalSymlinks so a symlinked checkout matches its real path.
func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
	target := canonicalPath(projectRoot)
	out := make([]LiveWorker, 0, len(workers))
	for _, w := range workers {
		if SamePath(w.ProjectRoot, target) {
			out = append(out, w)
		}
	}
	return out
}

// SamePath reports whether a and b refer to the same on-disk location after
// canonicalisation. It tolerates empty inputs (returning false) so callers
// can safely compare optional fields without prefiltering.
func SamePath(a, b string) bool {
	ca := canonicalPath(a)
	cb := canonicalPath(b)
	if ca == "" || cb == "" {
		return false
	}
	return ca == cb
}

func canonicalPath(p string) string {
	if strings.TrimSpace(p) == "" {
		return ""
	}
	abs, err := filepath.Abs(p)
	if err != nil {
		abs = filepath.Clean(p)
	}
	if resolved, err := filepath.EvalSymlinks(abs); err == nil {
		return resolved
	}
	return abs
}

// FormatAge renders a duration as a short human-readable string mirroring
// the conventions used by the server-backed worker list (`5s`, `12m`,
// `1h30m`). It is intended for terminal output; JSON output uses
// AgeSeconds as the numeric source of truth.
func FormatAge(d time.Duration) string {
	if d < time.Minute {
		if d < 0 {
			d = 0
		}
		return roundedSeconds(d)
	}
	if d < time.Hour {
		return roundedMinutes(d)
	}
	hours := int(d.Hours())
	mins := int(d.Minutes()) % 60
	if mins == 0 {
		return durationHours(hours)
	}
	return durationHoursMinutes(hours, mins)
}

func roundedSeconds(d time.Duration) string {
	secs := int(d.Seconds())
	return durationSeconds(secs)
}

func roundedMinutes(d time.Duration) string {
	mins := int(d.Minutes())
	return durationMinutes(mins)
}

func durationSeconds(n int) string { return formatUnit(n, "s") }
func durationMinutes(n int) string { return formatUnit(n, "m") }
func durationHours(n int) string   { return formatUnit(n, "h") }
func durationHoursMinutes(h, m int) string {
	return formatUnit(h, "h") + formatUnit(m, "m")
}

